output.sparql:
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?opponent ?opponentLabel WHERE {
  ?game wdt:P31 wd:Q206875 .
  {
    ?game wdt:P1446 wd:Q219714 ; wdt:P1441 ?opponent ; wdt:P1344 ?opponent .
  } UNION {
    ?game wdt:P1441 wd:Q219714 ; wdt:P1446 ?opponent ; wdt:P1344 ?opponent .
  }
  ?game wdt:P585 ?date .
  FILTER(?date >= "2023-09-01T00:00:00Z" ^^ xsd:dateTime && ?date <= "2024-02-15T00:00:00Z" ^^ xsd:dateTime)
  ?opponent rdfs:label ?opponentLabel .
  FILTER(lang(?opponentLabel) = 'en')
}
ORDER BY ?date

args.sparql:
SELECT ?opponent ?opponentLabel WHERE {
  ?game wdt:P710 wd:Q219714 ;  # Philadelphia Eagles
     wdt:P710 ?opponent ;
     wdt:P1344 ?opponent ;
     wdt:P585 ?date .

  FILTER (?opponent != wd:Q219714)
  FILTER (?date >= "2023-09-01T00:00:00Z"^^xsd:dateTime &&
          ?date <= "2024-02-15T00:00:00Z"^^xsd:dateTime)

  ?opponent rdfs:label ?opponentLabel .
  FILTER (lang(?opponentLabel) = 'en')
}
ORDER BY DESC(?date)
LIMIT 1

SELECT ?game ?opponent WHERE {
  ?game wdt:P710 wd:Q219714 .  # Philadelphia Eagles as participant
  ?game wdt:P710 ?opponent .
  ?game wdt:P31 wd:Q206875 .    # American football game
  FILTER (?opponent != wd:Q219714)
}

SELECT ?opponent ?opponentLabel WHERE {
  ?game wdt:P710 wd:Q219714 ;
        wdt:P3698 ?opponent .
  ?game wdt:P585 ?date .

  FILTER (?date >= "2023-09-01T00:00:00Z"^^xsd:dateTime &&
          ?date <= "2024-02-15T00:00:00Z"^^xsd:dateTime)

  ?opponent rdfs:label ?opponentLabel .
  FILTER (lang(?opponentLabel) = 'en')
}

SELECT ?opponent ?opponentLabel WHERE {
  ?game wdt:P31 wd:Q206875 .  # American football game

  {  
    ?game wdt:P674 wd:Q219714 ;  # Eagles as home team
          wdt:P675 ?opponent ;
          wdt:P1344 ?opponent .
  }
  UNION
  {
    ?game wdt:P675 wd:Q219714 ;  # Eagles as away team
          wdt:P674 ?opponent ;
          wdt:P1344 ?opponent .
  }

  ?game wdt:P585 ?date .
  FILTER(?date >= "2023-09-01T00:00:00Z"^^xsd:dateTime && 
         ?date <= "2024-02-15T00:00:00Z"^^xsd:dateTime)

  ?opponent rdfs:label ?opponentLabel .
  FILTER(lang(?opponentLabel) = 'en')
}

SELECT ?opponent ?opponentLabel WHERE {
  {
    ?game wdt:P1446 wd:Q219714 ;  # Eagles as home team
          wdt:P1441 ?opponent ;
          wdt:P1344 ?winner .
  }
  UNION
  {
    ?game wdt:P1441 wd:Q219714 ;  # Eagles as away team
          wdt:P1446 ?opponent ;
          wdt:P1344 ?winner .
  }
  ?game wdt:P31 wd:Q206875 .  # American football game
  ?game wdt:P585 ?date .

  FILTER (?winner = ?opponent)
  FILTER (?date >= "2023-09-01T00:00:00Z"^^xsd:dateTime && 
          ?date <= "2024-02-15T00:00:00Z"^^xsd:dateTime)

  ?opponent rdfs:label ?opponentLabel .
  FILTER (lang(?opponentLabel) = 'en')
}
ORDER BY ?date

